import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.function.Executable;
import org.mockito.Mockito;

import java.sql.ResultSet;
import java.sql.ResultSetMetaData;
import java.sql.SQLException;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

class CSVFormatTest {

    @Test
    void testWithHeader_withNullResultSet_returnsWithHeaderNull() throws SQLException {
        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader((ResultSet) null);
        CSVFormat expected = format.withHeader((ResultSetMetaData) null);
        assertEquals(expected, result);
    }

    @Test
    void testWithHeader_withResultSet_callsGetMetaDataAndReturnsWithHeader() throws SQLException {
        ResultSet resultSet = mock(ResultSet.class);
        ResultSetMetaData metaData = mock(ResultSetMetaData.class);
        when(resultSet.getMetaData()).thenReturn(metaData);

        CSVFormat format = CSVFormat.DEFAULT;
        CSVFormat result = format.withHeader(resultSet);
        CSVFormat expected = format.withHeader(metaData);

        verify(resultSet, times(1)).getMetaData();
        assertEquals(expected, result);
    }

    @Test
    void testWithHeader_withResultSet_throwsSQLException() throws SQLException {
        ResultSet resultSet = mock(ResultSet.class);
        when(resultSet.getMetaData()).thenThrow(new SQLException("MetaData exception"));

        CSVFormat format = CSVFormat.DEFAULT;
        SQLException thrown = assertThrows(SQLException.class, () -> format.withHeader(resultSet));
        assertEquals("MetaData exception", thrown.getMessage());
    }
}
